---@param skillData LBattleSkillData
function LBattleSkillPlayer:UpdateSkillData(skillData,tAtkUnitView,tBoutActionData)
    self._skillData = skillData

    if tAtkUnitView then
        self._atkUnitView = tAtkUnitView
    end

    if tBoutActionData then
        self._boutActionData = tBoutActionData
    end

    --- key:id
    --- effType:LSkillEffConst.PLAY_EFF_MOVE,LSkillEffConst.PLAY_EFF_EFFECT,
    ---			LSkillEffConst.PLAY_EFF_HIT_HUD,LSkillEffConst.PLAY_EFF_HUD
    ---@type table<string, table<number, boolean>>
    self._recordPosOnHookIdMap = {}

    self._isPosOnHook = false

    local playEffList = skillData:GetPlayEffList()
    local posOnHook = 0
    if skillData then
        posOnHook = skillData:GetPosOnHook()
    end
    if posOnHook == 1 then
        local viewMgr = self._viewMgr
        local dataMgr = viewMgr:GetDataMgr()

        ---@type LFightBoutActionData
        local boutActionData = self._boutActionData

        ---@type LFightObject
        local atkUnitView = self._atkUnitView

        local isAllbo,needShowNum = boutActionData:CheckIsAllbo()
        if isAllbo and needShowNum > 0 then
            self._isPosOnHook = true

            viewMgr:SetAllboTarget()

            local skillShowEff1List = skillData:GetSkillShowEff1List()
            local skillShowEff1Len = #skillShowEff1List
            local hasOtherEFF = skillShowEff1Len > 0

            local list = {}
            local recordTimeMap = {}
            local refId
            local playEffLen = #playEffList
            local copyNum = playEffLen - 1
            local calcLongTime
            local recordTime
            local playTime = 0
            local delayTime = 0
            local isFirst = false

            if hasOtherEFF then
                isFirst = true
                --- 第一招
                for i = 1,copyNum do
                    local data = skillData:CopySkillVfxRefData(playEffList[i])
                    refId = data.refId
                    playTime = data.playTime
                    delayTime = data.delayTime
                    calcLongTime = playTime
                    if not recordTime then
                        recordTime = calcLongTime
                        recordTimeMap[1] = recordTime
                    elseif recordTime < calcLongTime then
                        recordTime = calcLongTime
                        recordTimeMap[1] = recordTime
                    end
                    data.isEndSkill = false
                    table.insert(list, data)
                end

                --- 最后一招需要使用移动回去的时间
                local actorMoveBackData = skillData:CopySkillVfxRefData(playEffList[#playEffList])
                local endEffTime = actorMoveBackData.delayTime
                local interval = endEffTime - list[copyNum].delayTime

                --- 接下来的 n 招
                local otherShowNum = needShowNum - 1
                local atkSkin = atkUnitView:GetSkinId()
                local tempMap = {}
                local recordShowEff1List = {}
                local skinSkillType,cfg,skinToExpress,expressionId,expressionRef,needCheckSound
                for i,skillSkinRefId in ipairs(skillShowEff1List) do
                    skinSkillType = dataMgr:GetSkinSkillType(atkSkin,skillSkinRefId)
                    needCheckSound = skillData:IsNeedCheckSound(skinSkillType)
                    cfg = GameTable.SnakeSkillSkinRelationRef[skillSkinRefId]
                    skinToExpress = dataMgr:ParseSingleSkin(cfg.skinSkillExpression)
                    expressionId = skinToExpress[atkSkin]
                    expressionRef = skillData:GetSkillExpressionRef(expressionId)
                    table.insert(recordShowEff1List,skillData:ParsePlayEff(tempMap,expressionRef.playEff,atkSkin,needCheckSound))
                end

                local sortFunc = skillData:SortPlayEffectFunc()
                local tTime,trecordTime,tDelayTime
                local recordShowEff1Len = #recordShowEff1List
                local isOtherFirst = false
                local isOnlyKillOne = otherShowNum == 1
                for i = 1,otherShowNum do
                    playEffList = recordShowEff1List[i]
                    if not playEffList then
                        playEffList = recordShowEff1List[recordShowEff1Len]
                    end
                    table.sort(playEffList,sortFunc)
                    copyNum = #playEffList - 1
                    isOtherFirst = i == 1

                    local tempTime = 0.15 * i
                    for idx = 1,copyNum do
                        local data = skillData:CopySkillVfxRefData(playEffList[idx])
                        playTime = data.playTime
                        delayTime = data.delayTime
                        if isOtherFirst then
                            delayTime = delayTime + interval
                        end
                        if not isOnlyKillOne then
                            delayTime = delayTime - tempTime
                        end
                        --calcLongTime = playTime + delayTime
                        --- 不需要把 delayTime 计算进去，直接使用 playTime
                        calcLongTime = playTime

                        tTime = recordTimeMap[i] or 0
                        tTime = tTime - tempTime

                        trecordTime = tTime + calcLongTime
                        if recordTime < trecordTime then
                            recordTime = trecordTime
                            recordTimeMap[i + 1] = trecordTime
                        end
                        tDelayTime = tTime + delayTime
                        data.delayTime = tDelayTime

                        if i == otherShowNum and string.endswith(data.effRes, "_hit") then
                            data.isEndSkill = true
                        else
                            data.isEndSkill = false
                        end
                        table.insert(list, data)
                    end
                end
                local endEffectDatas = recordShowEff1List[#recordShowEff1List]
                local lastEffectData = endEffectDatas[#endEffectDatas]
                local moveBackData = skillData:CopySkillVfxRefData(lastEffectData)
                local endTime = 0
                if needShowNum ~= 1 then
                    local endBackIdx = needShowNum
                    if not recordTimeMap[endBackIdx] then
                        endBackIdx = #recordTimeMap
                    end
                    endTime = recordTimeMap[endBackIdx]
                end
                if not isOnlyKillOne then
                    endTime = endTime - otherShowNum * 0.2
                else
                    endTime = endTime + interval
                end
                moveBackData.delayTime = endTime
                table.insert(list, moveBackData)
            else
                for i = 1,needShowNum do
                    isFirst = i == 1
                    for idx = 1,copyNum do
                        local data = skillData:CopySkillVfxRefData(playEffList[idx])
                        refId = data.refId
                        playTime = data.playTime
                        delayTime = data.delayTime
                        calcLongTime = isFirst and playTime or playTime + delayTime
                        if isFirst then
                            if not recordTime then
                                recordTime = calcLongTime
                                recordTimeMap[i] = recordTime
                            elseif recordTime < calcLongTime then
                                recordTime = calcLongTime
                                recordTimeMap[i] = recordTime
                            end
                        else
                            local tTime = recordTimeMap[i - 1] or 0
                            local trecordTime = tTime + calcLongTime
                            if recordTime < trecordTime then
                                recordTimeMap[i] = trecordTime
                            end
                            data.delayTime = tTime + delayTime
                        end
                        if i == needShowNum and string.endswith(data.effRes, "_hit") then
                            data.isEndSkill = true
                        else
                            data.isEndSkill = false
                        end
                        table.insert(list, data)
                    end
                end
                local moveBackData = skillData:CopySkillVfxRefData(playEffList[playEffLen])
                local endTime = 0
                if needShowNum ~= 1 then
                    local endBackIdx = needShowNum - 1
                    if not recordTimeMap[endBackIdx] then
                        endBackIdx = needShowNum
                    end
                    endTime = recordTimeMap[endBackIdx]
                end
                moveBackData.delayTime = endTime + moveBackData.delayTime
                table.insert(list, moveBackData)
            end

            playEffList = list
        end
    end


    local hudNum = 0
    for i,v in ipairs(playEffList) do
        if v.effType == LSkillEffConst.PLAY_EFF_HIT_HUD or v.effType == LSkillEffConst.PLAY_EFF_HUD then
            hudNum = hudNum + 1
        end
    end
    self._playHudNum = hudNum
    self._playEffList = playEffList

    self._recordSpecialMap = {}

    ---{index = {index=k,refId=v.refId,isPlay = true, startTime = time, endTime = v.playTime + time, isFinished=false, childList={}},... }
    self._playStateList = {}

    self._isSkillFinished = false

    --- 是否相同的技能组
    self._bSameSkillGroup = false

    self._hudHurtIndexMap = {}

    self._startTime = nil

    --- 是否重置血条
    self._bResetBlock = false

    self:ParseActionEffectData() --预处理伤害数据
end


function LBattleSkillPlayer:Start(noSkillHud)
    self._startTime = nil
    self._isSkillFinished = false

    self._bSameSkillGroup = false
    self._bHideAtkObjHP = false
    if self._atkUnitView and self._atkUnitView:IsOnGridObj() then
        if self._skillData:IsSameSkillGroup() then
            ---skillEffGroup相同时，该组技能表现效果都隐藏血条和等级
            self._bHideAtkObjHP = true
            self._bSameSkillGroup = true
        elseif not self._skillData:IsNormal() and not (self._skillData:GetEffectType() == LFightConst.CALC_EFFECT_TYPE) then
            --释放技能时，当不是普攻和加血技能释放时，隐藏释放技能的对象血条和等级
            self._bHideAtkObjHP = true
        end
    end

    if not noSkillHud then
        self._showSkillHud = true
    end

    for k,v in ipairs(self._playEffList) do
        if v.effType == LSkillEffConst.PLAY_EFF_TREASURE then
            self:PrepareTreasure(v)
            self._isUpperLayer = true
            break
        end
    end

    self:OnPlayStart()
end

function LBattleSkillPlayer:GeneratePlayState(index, refId, startTime, endTime,hurtDataIndex)
    local playState = {
        index = index,
        refId = refId,
        isPlay = true,
        startTime = startTime,
        endTime = endTime,
        isFinished = false,
        childFinished = false,
        childList = {} ,
        leftEffects = nil,

        hurtDataType = 0,
        hurtDataIndex = hurtDataIndex,
    }
    return playState
end

function LBattleSkillPlayer:GenerateChildPlayState(effData, startTime, endTime)
    local playState = {
        effData = effData,
        isPlay = false,
        startTime = startTime,
        endTime = endTime,
        isFinished = false,
        --hurtDataType = 0,
        --hurtDataIndex = 1,
    }
    return playState
end
-----------------------------------------------------------------
function LBattleSkillPlayer:PreloadPlayList()
    for k, v in ipairs(self._playEffList) do
        self:DoPreloadEff(v)
        if v.nextPlayList then
            for k1,v1 in ipairs(v.nextPlayList) do
                self:DoPreloadEff(v1)
            end
        end

    end
end
-----------------------------------------------------------------
function LBattleSkillPlayer:CheckPlayList(time)
    local playStateList = self._playStateList
    local bFinishAll = true
    for k, v in ipairs(self._playEffList) do
        local playState = playStateList[k]
        if not playState then
            bFinishAll = false
            if v.delayTime <= time then
                --到了开始播放
                playState = self:GeneratePlayState(k, v.refId, time, v.playTime + time,v.effTargetIndex)
                playStateList[k] = playState
                if v.isEndSkill then
                    if self._viewMgr and self._viewMgr:IsLastAtk() then
                        self._viewMgr:BattleSkillEnd()
                    end
                end
                self:DoPlayEff(v, playState)
            end
        elseif not playState.isFinished then
            --检测结束状态
            local bChildFinished = playState.childFinished

            if not bChildFinished then
                bChildFinished = self:CheckChildPlayList(playState.childList,time)
                --if bChildFinished and playState.leftEffects then -- 防止遗漏的伤害没有播放
                --	self._viewMgr:DealShowHurt(playState.leftEffects)
                --end
            end

            playState.childFinished = bChildFinished

            local bTimeFinished = playState.endTime < time
            if bChildFinished and bTimeFinished then
                playState.isFinished = true
            else
                bFinishAll = false
            end
        end
    end

    return bFinishAll
end

--子弹技能跟随的播放列表
--childList 是通过GenerateChildPlaystate 建的结构
function LBattleSkillPlayer:CheckChildPlayList(childList, time)
    if not childList or #childList == 0 then
        return true
    end
    local bFinishAll = true
    for m, child in ipairs(childList) do
        if not child.isPlay then
            if child.startTime <= time then
                child.isPlay = true
                self:DoPlayEff(child.effData, child)
            end
        elseif not child.isFinished then
            child.isFinished = child.endTime < time
        end
        if not child.isFinished then
            bFinishAll = false
        end
    end
    return bFinishAll
end

local _Act_Fun_RegList = nil
local _Act_Fun_List = {}
function LBattleSkillPlayer:GetActFun(effType)
    if nil == _Act_Fun_RegList then
        _Act_Fun_RegList = {
            [LSkillEffConst.PLAY_EFF_MOVE] = "LBattleSkillActMove",
            [LSkillEffConst.PLAY_EFF_ANI] = "LBattleSkillActAni",
            [LSkillEffConst.PLAY_EFF_EFFECT] = "LBattleSkillActEffect",
            [LSkillEffConst.PLAY_EFF_BULLET] = "LBattleSkillActBullet",
            [LSkillEffConst.PLAY_EFF_HIT_HUD] = "LBattleSkillActHitWithHud",
            [LSkillEffConst.PLAY_EFF_HUD] = "LBattleSkillActHitWithHud",
            [LSkillEffConst.PLAY_EFF_SOUND] = "LBattleSkillActSound",
            [LSkillEffConst.PLAY_EFF_SHAKE] = "LBattleSkillActShake",
            [LSkillEffConst.PLAY_EFF_FADE] = "LBattleSkillActFade",
            [LSkillEffConst.PLAY_EFF_TOP_FADE] = "LBattleSkillActFadeTop",
            --[LSkillEffConst.PLAY_EFF_TREASURE] = "LBattleSkillActTreasure",
            [LSkillEffConst.PLAY_EFF_BUBBLE] = "LBattleSkillActBubble",
            [LSkillEffConst.PLAY_EFF_TREASURE_SKILL] = "LBattleSkillActTreasureSkill",
            [LSkillEffConst.PLAY_EFF_TREASURE_ICON] = "LBattleSkillActTreasureIcon",
            [LSkillEffConst.PLAY_EFF_FADE_EXTRA] = "LBattleSkillActFadeExtra",
            [LSkillEffConst.PLAY_EFF_DRAWING] = "LBattleSkillActDrawing",
            [LSkillEffConst.PLAY_EFF_FADE_TOP_EXTRA] = "LBattleSkillActFadeExtraTop",
            [LSkillEffConst.PLAY_EFF_HIT_MOVE] = "LBattleSkillActHitMove",
            [LSkillEffConst.PLAY_EFF_SHOW_FOCUS] = "LBattleSkillActShowFocus",
            [LSkillEffConst.PLAY_OBJ_TRANSFORM] = "LBattleSkillActObjTransform",
        }
    end

    local className = _Act_Fun_RegList[effType]
    if string.isempty(className) then
        return nil
    end

    local fun = _Act_Fun_List[effType]
    if not fun then
        local tmp = require("LApp.gameplay.videobattle.view.skillact."..className)
        fun = tmp.Execute
        _Act_Fun_List[effType] = fun
    end
    return fun
end

function LBattleSkillPlayer:DoPlayEff(effData, playState)
    local effType = effData.effType
    if not _Act_Fun_List then
        self:InitActFunList()
    end

    local fun = self:GetActFun(effType)

    if fun ~= nil then
        fun(self, effData, playState)
    else
        if LOG_INFO_ENABLED then
            printError("battle", "不支持的技能表现类型 : %s", tostring(effType))
        end
    end

    local soundName = effData.soundBattle
    if not string.isempty(soundName) then
        if self._atkUnitView and effData.needCheckSound then
            --- http://192.168.16.2:3002/issues/603
            soundName = self._atkUnitView:GetPlaySoundBattle(soundName,effData)
        end
        LxUiHelper.PlaySoundByName(soundName)
    end
end

