function LBattleSkillPlayer:DoPreloadEff(effData)
    local effType = effData.effType
    if LSkillEffConst.PRELOAD_EFFECT_MAP[effType] then
        self:PreloadPlayEffect(effData)
    elseif effType == LSkillEffConst.PLAY_EFF_TREASURE then
        self:PrepareTreasure(effData)
    end
end

function LBattleSkillPlayer:PreloadPlayEffect(effData)
    local effRes = effData.effRes --光效名字
    local resType = 1
    if effData.effType == LSkillEffConst.PLAY_EFF_DRAWING then
        resType = 2
    end

    local effectCtrl = self._viewMgr:GetEffectCtrl()
    local effTrans = self._viewMgr:GetEffectRootTrans()
    effectCtrl:PreloadEffectObject(effTrans,effRes,resType,nil,effData,self:GetTargetAtkUnitView())
end


