function LBattleSkillPlayer:GetEffStartPos(offsetType,selfSide,selfPos,targetPos)

    targetPos = targetPos or Vector3.zero

    local viewMgr = self._viewMgr
    local tempPos = selfPos
    if offsetType == LFightConst.EFFECT_TO_SELF then
        --1=自身
        tempPos = selfPos
    elseif offsetType == LFightConst.EFFECT_TO_EVERY_TAR then
        --2=针对指定单位
        tempPos = targetPos
    elseif offsetType == LFightConst.EFFECT_TO_TARGET_CENTER then
        --3=目标群体中心
        local actionHurtDataList = self._skillHurtDataList or {} --self:GetActionDataEffectByIndex(offsetTypeIndex) or {}
        local posTotal = Vector3(0, 0, 0)
        local posLen = 0
        for k, v in ipairs(actionHurtDataList) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local id = v1.hitHurt.eId
                    local tarObj = self._unitMgr:GetUnitView(id)
                    local tarPos = tarObj:GetPosition()
                    posTotal.x = posTotal.x + tarPos.x
                    posTotal.y = posTotal.y + tarPos.y
                    posLen = posLen + 1
                end
            end
        end
        if posLen > 0 then
            posTotal.x = posTotal.x / posLen
            posTotal.y = posTotal.y / posLen
        end
        tempPos = posTotal
    elseif offsetType == LFightConst.EFFECT_TO_SELF_TEAM_CENTER then
        --4=我方九宫中心格
        tempPos = self._viewMgr:GetFormationCenterPosition(selfSide):Clone()
    elseif offsetType == LFightConst.EFFECT_TO_ENEMY_TEAM_CENTER then
        --5=敌方九宫中心格
        tempPos = viewMgr:GetFormationCenterPosition(viewMgr:GetOppositeSide(selfSide)):Clone()
    elseif offsetType == LFightConst.EFFECT_TO_OFF_SCREEN_DOWN then
        --6=屏幕外下方
        tempPos = viewMgr:GetFormationOffScreenDownPosition(viewMgr:GetOppositeSide(selfSide)):Clone()
    elseif offsetType == LFightConst.EFFECT_TO_ZERO then
        --7=原点
        tempPos = Vector3.zero
    elseif offsetType == LFightConst.EFFECT_TO_ROW_CENTER then
        --9=目标排中心
        local side = BattleTeamSide.teamA
        local grid = 1
        local actionHurtDataList = self._skillHurtDataList or {}
        for k, v in ipairs(actionHurtDataList) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local id = v1.hitHurt.eId
                    local tarObj = self._unitMgr:GetUnitView(id)
                    side = tarObj:GetTeamIdx()
                    grid = tarObj:GetIndex()
                    break
                end
            end
        end
        tempPos = viewMgr:GetRowCenterPos(side,grid)
    end

    return tempPos
end

function LBattleSkillPlayer:GetFadeObj()
    if not self._fadeObjList then
        self._fadeObjList = {}
    end

    local fade = require("LApp.gameplay.videobattle.view.obj.LBattleViewFade"):new(self._viewMgr)
    table.insert(self._fadeObjList,fade)

    return fade
end

function LBattleSkillPlayer:OnFadeRun(time,deltaTime)
    if not self._fadeObjList then
        return
    end

    local cnt = #self._fadeObjList
    for k=cnt,1,-1 do
        local obj = self._fadeObjList[k]
        if not obj:OnUpdate(time, deltaTime) then
            obj:Dispose()
            table.remove(self._fadeObjList,k)
        end
    end
end

function LBattleSkillPlayer:FormatEffectData(effData,bulletData)
    local effectData = nil
    local obj = self:GetTargetAtkUnitView()
    if not obj then
        return effectData
    end

    local effTarget = effData.effTarget --目标类型
    local atkDir = obj:GetDirection()
    local viewMgr = self._viewMgr
    if effTarget == LFightConst.EFFECT_TO_SELF then
        --1=自身
        local dpTrans = obj:GetDpObject():GetDpTrans()
        local pos = obj:GetPosition():Clone()
        local tarId = self._atkUnitView:GetId()
        effectData = { trans = dpTrans, pos = pos, dir = obj:GetDirection(),isLocal = true,tarId = tarId}
    elseif effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
        --2=针对指定单位
        if bulletData then
            local tarObj = self._unitMgr:GetUnitView(bulletData.tarId)
            local pos = tarObj:GetPosition():Clone()
            local tran = tarObj:GetDpObject():GetDpTrans()
            effectData=  { trans = tran, pos = pos, dir = tarObj:GetDirection(),bulletData = bulletData,isLocal = true,tarId = bulletData.tarId}
        end
    elseif effTarget == LFightConst.EFFECT_TO_TARGET_CENTER then
        --3=目标群体中心
        local actionHurtDataList = self._skillHurtDataList or {} --self:GetActionDataEffectByIndex(effTargetIndex) or {}
        local posTotal = Vector3(0, 0, 0)
        local posLen = 0
        for k, v in ipairs(actionHurtDataList) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local id = v1.hitHurt.eId
                    local tarObj = self._unitMgr:GetUnitView(id)
                    local tarPos = tarObj:GetPosition()
                    posTotal.x = posTotal.x + tarPos.x
                    posTotal.y = posTotal.y + tarPos.y
                    posLen = posLen + 1
                end
            end
        end
        if posLen > 0 then
            posTotal.x = posTotal.x / posLen
            posTotal.y = posTotal.y / posLen
        end
        local effTrans = viewMgr:GetEffectRootTrans()
        effectData ={ trans = effTrans, pos = posTotal, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_SELF_TEAM_CENTER then
        --4=我方九宫中心格
        local effTrans = viewMgr:GetEffectRootTrans()
        local pos = viewMgr:GetFormationCenterPosition(obj:GetTeamIdx()):Clone()
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_ENEMY_TEAM_CENTER then
        --5=敌方九宫中心格
        local effTrans = viewMgr:GetEffectRootTrans()
        local pos = viewMgr:GetFormationCenterPosition(viewMgr:GetOppositeSide(obj:GetTeamIdx())):Clone()
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_OFF_SCREEN_DOWN then
        --6=屏幕外下方
        local effTrans = viewMgr:GetEffectRootTrans()
        local pos = viewMgr:GetFormationOffScreenDownPosition(viewMgr:GetOppositeSide(obj:GetTeamIdx())):Clone()
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_ZERO then
        --7=原点
        local effTrans = viewMgr:GetEffectRootTrans()
        local pos = Vector3.zero
        effectData = { trans = effTrans, pos = pos, dir = atkDir }
    elseif effTarget == LFightConst.EFFECT_TO_ROW_CENTER then
        --9=目标排中心
        local effTrans = viewMgr:GetEffectRootTrans()
        local side = BattleTeamSide.teamA
        local grid = 1
        local actionHurtDataList = self._skillHurtDataList or {}
        for k, v in ipairs(actionHurtDataList) do
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    local id = v1.hitHurt.eId
                    local tarObj = self._unitMgr:GetUnitView(id)
                    side = tarObj:GetTeamIdx()
                    grid = tarObj:GetIndex()
                    break
                end

            end
        end
        local pos = viewMgr:GetRowCenterPos(side,grid)
        effectData =  { trans = effTrans, pos = pos, dir = atkDir }
    else
        if ENABLE_FIGHT_LOG then
            printError("battle",string.format("动效终点目标错误 %s, refId = %s",tostring(effTarget), tostring(effData.refId)))
        end
    end

    return effectData
end

