function LBattleSkillPlayer:FormatShowHurtData(hurtList)
    if not hurtList then return end

    local hurtDataList = {
        baseEffectList = {}
    }
    local baseEffectList = hurtDataList.baseEffectList
    for k,v in ipairs(hurtList) do
        if v.beforeList then
            for k1,v1 in ipairs(v.beforeList) do
                table.insert(baseEffectList,v1)

                self:AddSpurtHurtData(baseEffectList,v1)
            end
        end

        table.insert(baseEffectList,v.hitHurt)

        self:AddSpurtHurtData(baseEffectList,v.hitHurt)

        if v.afterList then
            for k1,v1 in ipairs(v.afterList) do
                table.insert(baseEffectList,v1)

                self:AddSpurtHurtData(baseEffectList,v1)
            end
        end
    end

    return hurtDataList
end

---@param hurt LBattleBaseEffectData
function LBattleSkillPlayer:AddSpurtHurtData(list,hurt)
    local spurtingList = hurt.hurtEffect and hurt.hurtEffect.spurtingList
    if spurtingList then
        for k,v in ipairs(spurtingList) do
            table.insert(list, v)
        end
    end
end

function LBattleSkillPlayer:FormatSingleShowData(hurt)
    if not hurt then return end

    local hurtDataList ={baseEffectList={}}
    local baseEffectList = hurtDataList.baseEffectList
    if hurt.beforeList then
        for k,v in ipairs(hurt.beforeList) do
            table.insert(baseEffectList,v)
            self:AddSpurtHurtData(baseEffectList,v)
        end
    end

    table.insert(baseEffectList,hurt.hitHurt)

    self:AddSpurtHurtData(baseEffectList,hurt.hitHurt)

    if hurt.afterList then
        for k,v in ipairs(hurt.afterList) do
            table.insert(baseEffectList,v)
            self:AddSpurtHurtData(baseEffectList,v)
        end
    end

    return hurtDataList
end


---以hitType == 1 为节点划分伤害数据，防止顺序错乱
function LBattleSkillPlayer:ParseActionEffectData()
    local effectList = self._boutActionData.effectArrays

    local skillHurtDataList = {}
    local normalHurtDataList ={}
    local tempSDataList ={}
    local hitHeros = {}
    local spurtingHitHeros = {}
    local recordNoSkillHurtMap = {}

    for k,v in ipairs(effectList) do
        local normalList = {}
        local tempIndex = 1
        for k1,v1 in ipairs(v.effectListArray) do   --查询技能表现需要的伤害数据
            local isSkillHurt = false
            local skillHurtList = {}
            local tempSList = {}
            local hasHitType = false

            local index = 1

            for k2,v2 in ipairs(v1.baseEffectList) do
                local hurtEffect = v2.hurtEffect
                isSkillHurt = v2.hitType == 1
                if isSkillHurt then
                    hitHeros[v2.eId] = true
                    local data = {
                        beforeList = normalList,
                        hitHurt = v2,
                    }
                    table.insert(skillHurtList,data)
                    table.insert(tempSList,{index = index,data = data}) --初始数据镜像
                    index = index + 1
                    normalList ={}
                    hasHitType = true
                else
                    if hurtEffect and hurtEffect.dead then
                        recordNoSkillHurtMap[v2.eId] = v2
                    end
                    table.insert(normalList,v2)
                end

                --- 溅射英雄记录
                local spurtingList = hurtEffect and hurtEffect.spurtingList
                if spurtingList and #spurtingList > 0 then
                    for k3,v3 in ipairs(spurtingList) do
                        isSkillHurt = v3.hitType == 1
                        local v3hurtEffect = v3.hurtEffect
                        if not isSkillHurt then
                            --- 溅射加成需要显示角色
                            if v3hurtEffect and v3hurtEffect.ht == LFightConst.HURT_TYPE_SPUTTERING then
                                isSkillHurt = true
                            end
                        end
                        if isSkillHurt then
                            local data = {
                                beforeList = normalList,
                                hitHurt = v3,
                            }
                            table.insert(spurtingHitHeros,data)
                        end
                    end
                end

            end
            if #normalList > 0 then
                local last = skillHurtList[#skillHurtList]
                if last then
                    for idx,val in ipairs(normalList) do
                        recordNoSkillHurtMap[val.eId] = nil
                    end
                    last.afterList = normalList
                    normalList = {}
                end
            end
            if #skillHurtList > 0 then
                table.insert(skillHurtDataList,skillHurtList)
                table.insert(tempSDataList,{index = tempIndex,dataList = tempSList})
                tempIndex = tempIndex + 1
            end
        end
        if #normalList>0 then
            table.insert(normalHurtDataList,normalList)
        end
    end

    self._skillHurtDataList = skillHurtDataList
    self._normalHurtDataList = normalHurtDataList
    self._spurtingHitHeros = spurtingHitHeros

    self._recordNoSkillHurtMap = recordNoSkillHurtMap

    self._tempSDataList = tempSDataList

    self._hitHeros = hitHeros
end

function LBattleSkillPlayer:ShowRemainEffect()

    local dataList ={}
    if self._tempSDataList then
        for k,v in pairs(self._tempSDataList) do
            table.insert(dataList,v)
        end
        table.sort(dataList,function (a,b)
            return a.index<b.index
        end)

        local tempList ={}
        for k,v in ipairs(dataList) do
            local tempTempList = {}
            for k1,v1 in pairs(v.dataList) do
                table.insert(tempTempList,v1)
            end

            table.sort(tempTempList,function (a,b)
                return a.index < b.index
            end)

            local list = {}
            for k1,v1 in ipairs(tempTempList) do
                table.insert(list,v1.data)
            end

            local data = self:FormatShowHurtData(list)
            table.insert(tempList,data)
        end

        if #tempList>0 then
            self._viewMgr:DealShowHurt({effectListArray = tempList}, LFightConst.PLAY_HIT_ACTION_NONE,nil)
        end
    end


    local normalList = {}
    for k,v in ipairs(self._normalHurtDataList) do
        local data ={baseEffectList={}}
        local baseEffectList = data.baseEffectList
        for k1,v1 in ipairs(v) do
            table.insert(baseEffectList,v1)
            self:AddSpurtHurtData(baseEffectList,v1)
        end

        table.insert(normalList,data)
    end

    if #normalList>0 then
        self._viewMgr:DealShowHurt({effectListArray = normalList}, LFightConst.PLAY_HIT_ACTION_NONE,nil)
    end
end


------------------------------------------------------------------
---技能名字HUD
function LBattleSkillPlayer:CreateSkillHUD()
    if not self._showSkillHud then
        return
    end

    self._showSkillHud = false

    local isNormal = self._skillData:IsNormal()
    if isNormal then
        return
    end

    if not self._skillData:IsShowSkillHud() then
        return
    end

    --local skillNameImage = self._skillData:GetSkillNameImage()
    --if string.isempty(skillNameImage) then
    --	return
    --end
    local obj = self._atkUnitView
    if not obj then return end

    if not obj:IsOnGridObj() then return end

    --local objType = obj:GetObjectType()
    local pos = nil
    local changeType = nil
    local skillId = self._skillData:GetSkillRefId()


    --local tarPos = obj:GetTopNodePos()
    local tarPos = obj:GetPosition()--技能飘字改成从腿部出现
    pos = tarPos and tarPos:Clone() or Vector3.zero
    changeType = LFightConst.HURT_TYPE_SKILL
    --elseif objType == LFightConst.OBJ_TREASURE then
    --	pos = Vector3.New(0,3,0)
    --	changeType = LFightConst.HURT_TREA


    local heroRace = obj:GetHeroRaceType()
    --技能飘字从腿部出现, 左边从左到右，右边从右到左
    local anim = obj:GetTeamIdx() == BattleTeamSide.teamA and LFightConst.HUD_ANIM_LEFT_TO_RIGHT or LFightConst.HUD_ANIM_RIGHT_TO_LEFT
    local time = self._viewMgr:GetTime()
    local delaySkillHudTime = self:GetSkillHudDelayTime()
    time = time + delaySkillHudTime
    local hunData = {
        pos = pos,
        time = time,
        changeType = changeType,
        playNum ={},
        skillId = skillId,
        animation = anim,
        heroRace = heroRace,
        isLeft = obj:GetTeamIdx() == BattleTeamSide.teamA,
    }
    obj:ShowSkillNameHud(hunData,time)
end

function LBattleSkillPlayer:GetSkillHudDelayTime()
    local time = 0
    local otherTime = 0
    local isStartCalc = false
    local playTime
    local playEffList = self._playEffList or {}
    for i,v in ipairs(playEffList) do
        playTime = v.playTime
        if v.effType == LSkillEffConst.PLAY_EFF_DRAWING then
            if not isStartCalc then
                isStartCalc = true
            end
            if playTime > time then
                if otherTime > 0 and otherTime > playTime then
                    time = otherTime
                else
                    time = playTime
                end
            end
        else
            if isStartCalc then break end

            if playTime > otherTime then
                otherTime = playTime
            end
        end
    end
    return time
end

------------------------------------------------------------------
function LBattleSkillPlayer:OnUpdate(time, deltaTime)
    if self._isDisposed then
        return false
    end

    if self._isSkillFinished then
        return false
    end

    local isOk = self:OnTreasureRun(time)
    if not isOk then
        return true
    end

    if self:CheckWaitSummon() then
        return true
    end

    if not self._startTime then
        self._startTime = time
    end

    if self._showSkillHud then
        self:CreateSkillHUD()
    end

    self:OnFadeRun(time, deltaTime)

    if not self:CheckPlayList(time - self._startTime) then
        return true
    end

    self:ShowRemainEffect()

    self._isSkillFinished = true
    return false
end

function LBattleSkillPlayer:GetSkillId()
    return self._skillData:GetSkillRefId()
end

function LBattleSkillPlayer:GetSkillEffId()
    return self._skillData:GetSkillEffId()
end

function LBattleSkillPlayer:GetTargetTran(id)
    local obj = self._unitMgr:GetUnitView(id)
    if not obj then
        return nil
    end
    local dpObj = obj:GetDpObject()
    if not dpObj then
        return nil
    end
    local tran = dpObj:GetDpTrans()
    return tran
end

function LBattleSkillPlayer:GetTargetTranPos(id)
    local obj = self._unitMgr:GetUnitView(id)
    if not obj then
        return Vector3.zero
    end
    local tarPos = obj:GetPosition()
    tarPos = tarPos:Clone()
    return tarPos
end

function LBattleSkillPlayer:GetTargetDirection(id)
    local obj = self._unitMgr:GetUnitView(id)
    if not obj then
        return LFightConst.DIRECTION_RIGHT

    end
    return obj:GetDirection()

end

function LBattleSkillPlayer:GetTargetAtkUnitView()
    if self._treasureObj then
        return self._treasureObj
    else
        return self._atkUnitView
    end

end

function LBattleSkillPlayer:PrepareTreasure(effData)
    if self._treasureObj then
        return
    end
    local side = self._atkUnitView:GetTeamIdx()
    local pos = self._viewMgr:GetFormationCenterPosition(side):Clone()
    local startX = LBattleSkillPlayer.BORN_OFFSET
    pos = Vector3.New(-startX,pos.y,pos.z)
    if side == BattleTeamSide.teamB then
        pos = Vector3.New(startX,pos.y,pos.z)
    end
    local treaCtrl = self._viewMgr:GetTreasureObjCtrl()
    local heroId = self._atkUnitView:GetId()
    self._treasureObj = treaCtrl:LoadObj(heroId,effData)
    self._treasureObj:SetPara({side = side,pos = pos})

end

function LBattleSkillPlayer:OnTreasureRun(time)
    if not self._treasureObj then
        return true
    end

    if self._treasureObj:IsObjReady() then
        self._treasureObj:OnRun(time)
        return true
    end
end

function LBattleSkillPlayer:CheckWaitSummon()
    if self._atkUnitView then
        local isReady = self._atkUnitView:IsObjReady()
        if not isReady then
            return true
        end
    end
end

function LBattleSkillPlayer:OnPlayEnd()
    if self._fadeObjList then
        for k,v in pairs(self._fadeObjList) do
            v:Dispose()
        end
        self._fadeObjList=nil
    end

    local objectType = self._atkUnitView:GetObjectType()
    if objectType == LFightConst.OBJ_TREASURE then
        local side = self._atkUnitView:GetTeamIdx()
        local objList = self._viewMgr:GetUnitMgr():GetUnitMap(side)
        for k,v in pairs(objList) do
            v:ResetRender()
            v:ReleaseHideKey("treasure")
        end

        self:ChangeHitHeroLayer(2)


        local heroData = self._atkUnitView:GetHeroData()
        local skillId = self._skillData:GetSkillRefId()
        heroData:OnTreasureSkillEnd(skillId)
        self._atkUnitView:ResetAlpha()

        if self._treasureObj then
            self._treasureObj:SetPosition(Vector3.New(6,0,0))
            self._treasureObj:ResetAlpha()
        end

    else
        self._atkUnitView:OnSkillEnd()
        if self._bResetBlock then
            --- 需要重新显示血条
            self._atkUnitView:ReleaseHideKey("skillUse")
        end
    end

end

function LBattleSkillPlayer:OnPlayStart()
    local objectType = self._atkUnitView:GetObjectType()
    local side = self._atkUnitView:GetTeamIdx()
    if objectType == LFightConst.OBJ_TREASURE then
        local treaObj = self:GetTargetAtkUnitView()
        treaObj:SetRenderOrder(LFightConst.TOP_ORDER)

        self:ChangeHitHeroLayer(1)

        local objList = self._viewMgr:GetUnitMgr():GetUnitMap(side)
        for k,v in pairs(objList) do
            local id = v:GetId()
            if not self._hitHeros[id] then
                --v:HideBlood()
                v:SetHideBloodKey("treasure")
            end
        end

    else
        self._atkUnitView:SetRenderOrder(LFightConst.TOP_ORDER)
        if self._bHideAtkObjHP then
            --self._atkUnitView:HideBlood()
            self._atkUnitView:SetHideBloodKey("skillUse")
            self._atkUnitView:ShowBuffEffect(false)
        end
        self._atkUnitView:SetIsSameSkillGroup(self._bSameSkillGroup)
        self._atkUnitView:OnSkillStart()
    end
end


function LBattleSkillPlayer:GetScale()
    if self._atkUnitView then
        return self._atkUnitView:GetObjScale() or 1
    end
    return self._scale or 1
end

function LBattleSkillPlayer:ChangeHitHeroLayer(layerType)
    if not self._hitHeros then
        return
    end
    for k,v in pairs(self._hitHeros) do
        local heroId = k
        local obj = self._unitMgr:GetUnitView(heroId)
        if obj then
            if layerType == 1 then
                obj:ToUpperLayer()
            elseif layerType == 2 then
                obj:ResetRender()
            end
        end
    end
end

function LBattleSkillPlayer:HideAllBlood()
    local objCtrl = self._viewMgr:GetUnitMgr()
    local objList = objCtrl:GetUnitMap() or {}
    for k,v in pairs(objList) do
        if v:IsNormalObj() then
            v:SetHideBloodKey("drawing")
        end
    end
end

function LBattleSkillPlayer:RecoverBloodShow()
    local objCtrl = self._viewMgr:GetUnitMgr()
    local objList = objCtrl:GetUnitMap() or {}
    for k,v in pairs(objList) do
        if v:IsNormalObj() then
            v:ReleaseHideKey("drawing")
        end
    end
end

function LBattleSkillPlayer:IsUpperLayer(heroId)
    if self._isUpperLayer then
        return true
    end
    if not heroId then
        return
    end
    local obj = self._unitMgr:GetUnitView(heroId)
    if obj then
        return obj:IsUpperLayer()
    end
end

function LBattleSkillPlayer:NeedResetBlock(bReset)
    ---#570 skillEffGroup相同时，该组技能表现效果都隐藏血条和等级
    self._bResetBlock = bReset
end

function LBattleSkillPlayer:UpdateHeroesBgState()
    if self._hitHeros then
        for k,v in pairs(self._hitHeros) do
            local heroId = k
            local obj = self._unitMgr:GetUnitView(heroId)
            if obj then
                obj:SetHeroBg_Hit()
            end
        end
    end
    if self._atkUnitView then
        self._atkUnitView:SetHeroBg_Attack()
    end
end

function LBattleSkillPlayer:ResetHeroesBgState()
    if self._hitHeros then
        for k,v in pairs(self._hitHeros) do
            local heroId = k
            local obj = self._unitMgr:GetUnitView(heroId)
            if obj then
                obj:SetHeroBg_Normal()
            end
        end
    end
    if self._atkUnitView then
        self._atkUnitView:SetHeroBg_Normal()
    end
end

-----------------------------------------------------------------
function LBattleSkillPlayer:IsDisposed()
    return self._isDisposed
end

function LBattleSkillPlayer:Dispose()
    if self._isDisposed then return end
    self:OnPlayEnd()
    table.dispose(self)
    self._isDisposed = true
end

return LBattleSkillPlayer